
DROP FUNCTION IF EXISTS public.update_task_progress(text, integer, integer);
CREATE FUNCTION public.update_task_progress(_task_type text, _value integer DEFAULT NULL, _increment integer DEFAULT NULL) RETURNS json LANGUAGE plpgsql SECURITY DEFINER SET search_path = public SET statement_timeout = '5s' AS $$ DECLARE _user_id uuid; _today text; _task RECORD; _new_progress integer; _is_completed boolean; _is_host boolean; _has_active_stream boolean; _results jsonb := '[]'::jsonb; BEGIN _user_id := auth.uid(); IF _user_id IS NULL THEN RETURN json_build_object('success', false, 'error', 'Not authenticated'); END IF; _today := to_char((now() AT TIME ZONE 'UTC' - interval '30 minutes')::date, 'YYYY-MM-DD'); IF _task_type IN ('first_live','live_minutes','viewers','first_gift') THEN SELECT is_host INTO _is_host FROM profiles WHERE id = _user_id; IF NOT COALESCE(_is_host, false) THEN RETURN json_build_object('success', false, 'error', 'Not a host'); END IF; SELECT EXISTS(SELECT 1 FROM live_streams WHERE host_id = _user_id AND is_active = true AND ended_at IS NULL AND created_at > now() - interval '24 hours') INTO _has_active_stream; IF NOT _has_active_stream THEN RETURN json_build_object('success', false, 'error', 'No active live stream'); END IF; END IF; FOR _task IN SELECT id, requirement_value FROM daily_tasks WHERE requirement_type = _task_type AND is_active = true LOOP IF _value IS NOT NULL THEN _new_progress := _value; ELSIF _increment IS NOT NULL THEN _new_progress := _increment; ELSE _new_progress := 1; END IF; _is_completed := _new_progress >= _task.requirement_value; INSERT INTO user_task_progress (user_id, task_id, reset_date, current_progress, is_completed) VALUES (_user_id, _task.id, _today, _new_progress, _is_completed) ON CONFLICT (user_id, task_id, reset_date) DO UPDATE SET current_progress = CASE WHEN user_task_progress.is_claimed THEN user_task_progress.current_progress WHEN _value IS NOT NULL THEN GREATEST(user_task_progress.current_progress, _value) ELSE COALESCE(user_task_progress.current_progress, 0) + COALESCE(_increment, 1) END, is_completed = CASE WHEN user_task_progress.is_claimed THEN user_task_progress.is_completed ELSE (CASE WHEN _value IS NOT NULL THEN GREATEST(user_task_progress.current_progress, _value) ELSE COALESCE(user_task_progress.current_progress, 0) + COALESCE(_increment, 1) END) >= _task.requirement_value END, updated_at = now() RETURNING current_progress, is_completed INTO _new_progress, _is_completed; _results := _results || jsonb_build_object('task_id', _task.id, 'progress', _new_progress, 'completed', _is_completed); END LOOP; RETURN json_build_object('success', true, 'tasks', _results); END; $$;
GRANT EXECUTE ON FUNCTION public.update_task_progress TO authenticated;
